package managementasset

import (
	"bytes"
)

const xaiFreeUsageWidgetMarker = "cliproxy-xai-free-usage-page-extension"

func InjectXAIFreeUsageWidget(html []byte) []byte {
	if len(html) == 0 || bytes.Contains(html, []byte(xaiFreeUsageWidgetMarker)) {
		return html
	}
	asset := []byte(xaiFreeUsagePageHTML)
	if index := bytes.LastIndex(bytes.ToLower(html), []byte("</body>")); index >= 0 {
		out := make([]byte, 0, len(html)+len(asset))
		out = append(out, html[:index]...)
		out = append(out, asset...)
		out = append(out, html[index:]...)
		return out
	}
	return append(append([]byte(nil), html...), asset...)
}

func HasXAIFreeUsageWidget(html []byte) bool {
	return bytes.Contains(html, []byte(xaiFreeUsageWidgetMarker))
}

const xaiFreeUsagePageHTML = `
<style id="cliproxy-xai-free-usage-page-extension-style">
#cliproxy-xai-free-usage-page{position:fixed;z-index:1000;overflow:auto;background:#171717;color:#f1f5f9;font:14px/1.5 system-ui,-apple-system,"Segoe UI",sans-serif;padding:28px 30px 40px;box-sizing:border-box}.cxu-page-head{display:flex;align-items:flex-start;justify-content:space-between;gap:18px;margin-bottom:22px}.cxu-page-title{font-size:26px;font-weight:750;margin:0}.cxu-page-subtitle,.cxu-muted{color:#94a3b8}.cxu-page-subtitle{margin-top:5px}.cxu-actions{display:flex;align-items:center;gap:12px;flex-wrap:wrap}.cxu-refresh,.cxu-page-button{border:1px solid #475569;border-radius:9px;background:#1e293b;color:#f8fafc;padding:8px 14px;cursor:pointer}.cxu-refresh:hover,.cxu-page-button:hover{background:#334155}.cxu-refresh:disabled,.cxu-page-button:disabled{cursor:not-allowed;opacity:.45}.cxu-summary{display:flex;gap:10px;flex-wrap:wrap;margin-bottom:18px}.cxu-pill{border:1px solid #334155;border-radius:999px;background:#1e293b;padding:5px 10px;color:#cbd5e1}.cxu-controls{display:flex;align-items:center;gap:12px;flex-wrap:wrap;margin-bottom:18px}.cxu-control{display:flex;align-items:center;gap:7px;color:#cbd5e1}.cxu-select{border:1px solid #475569;border-radius:8px;background:#1e293b;color:#f8fafc;padding:6px 9px}.cxu-error{margin-bottom:16px;border:1px solid #7f1d1d;border-radius:10px;background:#450a0a;color:#fecaca;padding:10px 12px}.cxu-grid{display:grid;grid-template-columns:repeat(var(--cxu-columns),minmax(0,1fr));gap:16px}.cxu-card{min-width:0;border:1px solid #374151;border-radius:14px;background:#202020;padding:18px;box-shadow:0 7px 22px rgba(0,0,0,.16)}.cxu-card-head{display:flex;justify-content:space-between;gap:12px}.cxu-email{font-size:16px;font-weight:700;overflow-wrap:anywhere}.cxu-badge{flex:none;border:1px solid #047857;border-radius:999px;background:#064e3b;color:#6ee7b7;font-size:12px;padding:2px 8px;height:max-content}.cxu-badge-warn{border-color:#92400e;background:#451a03;color:#fcd34d}.cxu-quota{margin-top:18px}.cxu-quota-head{display:flex;justify-content:space-between;gap:12px;margin-bottom:7px}.cxu-quota-value{font-weight:700;font-variant-numeric:tabular-nums}.cxu-track{height:10px;border-radius:999px;background:#374151;overflow:hidden}.cxu-fill{height:100%;border-radius:inherit;transition:width .25s ease}.cxu-green{background:linear-gradient(90deg,#16a34a,#4ade80)}.cxu-yellow{background:linear-gradient(90deg,#ca8a04,#facc15)}.cxu-red{background:linear-gradient(90deg,#dc2626,#fb7185)}.cxu-meta{margin-top:16px;padding-top:13px;border-top:1px solid #374151;color:#94a3b8;font-size:12px}.cxu-state{margin-top:18px;border:1px dashed #475569;border-radius:10px;padding:22px;text-align:center;color:#94a3b8}.cxu-empty{border:1px dashed #475569;border-radius:14px;padding:48px 20px;text-align:center;color:#94a3b8}.cxu-pager{display:flex;align-items:center;justify-content:center;gap:10px;margin-top:20px;flex-wrap:wrap}.cxu-nav-active{background:rgba(59,130,246,.14)!important;color:#e0f2fe!important}.cxu-nav-icon{display:inline-flex;align-items:center;justify-content:center;width:22px;height:22px;font-weight:800;color:#38bdf8}
@media(max-width:900px){#cliproxy-xai-free-usage-page{padding:20px 16px 30px}.cxu-page-head{flex-direction:column}.cxu-actions{width:100%;justify-content:space-between}}
</style>
<script id="cliproxy-xai-free-usage-page-extension">
(()=>{
const ROUTE='#/auth-files?xai-free-usage=1',PAGE_ID='cliproxy-xai-free-usage-page',NAV_ID='cliproxy-xai-free-usage-nav',INTERVAL=30000;
if(window.__cliproxyXAIFreeUsagePage)return;window.__cliproxyXAIFreeUsagePage=true;
let page=null,nav=null,timer=null,countdown=null,nextRefresh=0,inFlight=false,lastAccounts=null,lastRefresh=null,observer=null,currentPage=1,effectiveColumns=1;
const COLUMN_KEY='cliproxy-xai-free-columns',ROWS_KEY='cliproxy-xai-free-rows',AUTO_REFRESH_KEY='cliproxy-xai-free-auto-refresh',columnOptions=['auto','1','2','3','4'],rowOptions=[1,2,3,4,5];
let columnPreference=columnOptions.includes(localStorage.getItem(COLUMN_KEY))?localStorage.getItem(COLUMN_KEY):'auto',rowsPerPage=rowOptions.includes(Number(localStorage.getItem(ROWS_KEY)))?Number(localStorage.getItem(ROWS_KEY)):2,autoRefreshEnabled=false;
autoRefreshEnabled=localStorage.getItem(AUTO_REFRESH_KEY)==='true';
const authLabels=['认证文件','Auth Files','認證文件'],oauthLabels=['OAuth 登录','OAuth Login','OAuth 登入'];
const text=e=>(e&&e.textContent||'').trim();
const exact=(labels)=>[...document.querySelectorAll('a,button,[role="link"],[role="button"]')].find(e=>labels.some(label=>text(e).includes(label)));
const active=()=>location.hash===ROUTE;
const escapeHTML=v=>String(v??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
const fmt=v=>new Intl.NumberFormat().format(Number(v||0));
const decode=v=>{if(!v.startsWith('enc::v1::'))return v;try{const raw=atob(v.slice(9)),seed=new TextEncoder().encode('cli-proxy-api-webui::secure-storage|'+location.host+'|'+navigator.userAgent),out=new Uint8Array(raw.length);for(let i=0;i<raw.length;i++)out[i]=raw.charCodeAt(i)^seed[i%seed.length];return new TextDecoder().decode(out)}catch{return ''}};
const storedValue=v=>{v=decode(v);try{const parsed=JSON.parse(v);return typeof parsed==='string'?parsed:parsed&&typeof parsed.managementKey==='string'?parsed.managementKey:''}catch{return v}};
const managementKey=()=>{for(const storage of [localStorage,sessionStorage])for(let i=0;i<storage.length;i++){const name=storage.key(i)||'',raw=storage.getItem(name)||'',direct=/management.?key/i.test(name)?storedValue(raw).trim():'';if(direct)return direct;try{const parsed=JSON.parse(decode(raw)),state=parsed&&parsed.state;if(parsed&&typeof parsed.managementKey==='string'&&parsed.managementKey.trim())return parsed.managementKey.trim();if(state&&typeof state.managementKey==='string'&&state.managementKey.trim())return state.managementKey.trim()}catch{}}return ''};
const findSidebar=()=>{const auth=exact(authLabels);if(!auth)return null;let node=auth;while(node&&node!==document.body){const rect=node.getBoundingClientRect();if(rect.left<=8&&rect.width>=180&&rect.width<=420&&rect.height>innerHeight*.55)return node;node=node.parentElement}return auth.closest('aside,nav')};
const findMain=()=>document.querySelector('main')||document.querySelector('[role="main"]')||[...document.body.children].find(e=>{const r=e.getBoundingClientRect();return r.width>innerWidth*.55&&r.height>innerHeight*.55&&r.left>100});
const positionPage=()=>{if(!page)return;const main=findMain(),mainRect=main?main.getBoundingClientRect():{left:280,top:0,right:innerWidth,bottom:innerHeight},sidebar=findSidebar(),sidebarRect=sidebar?sidebar.getBoundingClientRect():{right:0},left=Math.max(mainRect.left,sidebarRect.right);page.style.left=Math.max(0,left)+'px';page.style.top=Math.max(0,mainRect.top)+'px';page.style.width=Math.max(320,innerWidth-Math.max(0,left))+'px';page.style.height=Math.max(320,innerHeight-Math.max(0,mainRect.top))+'px'};
const replaceLabel=(root,from,to)=>{const walker=document.createTreeWalker(root,NodeFilter.SHOW_TEXT);let node;while(node=walker.nextNode())if((node.nodeValue||'').includes(from))node.nodeValue=node.nodeValue.replace(from,to)};
function ensureNav(){const auth=exact(authLabels);if(!auth)return;nav=document.getElementById(NAV_ID);if(!nav){nav=auth.cloneNode(true);nav.id=NAV_ID;nav.removeAttribute('aria-current');nav.querySelectorAll('[id]').forEach(e=>e.removeAttribute('id'));for(const label of authLabels)replaceLabel(nav,label,'Grok Free 额度');if(!text(nav).includes('Grok Free 额度'))nav.innerHTML='<span class="cxu-nav-icon">G</span><span>Grok Free 额度</span>';nav.setAttribute('href',ROUTE);nav.addEventListener('click',event=>{event.preventDefault();event.stopPropagation();event.stopImmediatePropagation();if(location.hash!==ROUTE)location.hash=ROUTE;syncRoute()},true);const oauth=exact(oauthLabels);if(oauth&&oauth.parentElement===auth.parentElement)auth.parentElement.insertBefore(nav,oauth);else auth.insertAdjacentElement('afterend',nav)}nav.classList.toggle('cxu-nav-active',active())}
const ratio=limit=>remaining=>limit>0?Math.max(0,Math.min(100,remaining/limit*100)):0;
const calculateColumns=()=>{if(!page)return 1;const width=Math.max(280,page.clientWidth-60),maximum=Math.max(1,Math.min(4,Math.floor((width+16)/360)));return columnPreference==='auto'?maximum:Math.max(1,Math.min(Number(columnPreference),maximum))};
const paginate=accounts=>{effectiveColumns=calculateColumns();const pageSize=Math.max(1,effectiveColumns*rowsPerPage),totalPages=Math.max(1,Math.ceil(accounts.length/pageSize));currentPage=Math.max(1,Math.min(currentPage,totalPages));const start=(currentPage-1)*pageSize;return{items:accounts.slice(start,start+pageSize),pageSize,totalPages}};
const optionHTML=(values,selected,label)=>values.map(value=>'<option value="'+value+'" '+(String(value)===String(selected)?'selected':'')+'>'+label(value)+'</option>').join('');
const quota=(label,value,note='')=>{const limit=Number(value.limit||0),remaining=Math.max(0,Math.min(limit,Number(value.remaining||0))),pct=ratio(limit)(remaining),color=pct<20?'cxu-red':pct<=50?'cxu-yellow':'cxu-green';return '<div class="cxu-quota"><div class="cxu-quota-head"><span>'+label+'最近上游剩余</span><span class="cxu-quota-value">'+fmt(remaining)+' / '+fmt(limit)+'</span></div><div class="cxu-track"><div class="cxu-fill '+color+'" style="width:'+pct+'%"></div></div><div class="cxu-muted">上游报告：'+fmt(value.remaining)+' / '+fmt(limit)+(note?' · '+note:'')+'</div></div>'};
const card=account=>{const identity=escapeHTML(account.email||account.id);if(!account.free_mode)return '<article class="cxu-card"><div class="cxu-card-head"><div class="cxu-email">'+identity+'</div><span class="cxu-badge cxu-badge-warn">自定义路径</span></div><div class="cxu-state">该账号未使用 Grok Free 路径</div></article>';if(!account.known)return '<article class="cxu-card"><div class="cxu-card-head"><div class="cxu-email">'+identity+'</div><span class="cxu-badge">Free</span></div><div class="cxu-state">等待首次真实请求</div></article>';const updated=account.updated_at?new Date(account.updated_at).toLocaleString():'--',observedTokens=account.observed_tokens&&account.observed_tokens.total||0,observedRequests=account.observed_requests||0,requestNote=observedRequests?'升级后已记录 '+fmt(observedRequests)+' 次':'请求计数从本次升级后开始';return '<article class="cxu-card"><div class="cxu-card-head"><div><div class="cxu-email">'+identity+'</div><div class="cxu-muted">'+escapeHTML(account.last_model||'尚无模型记录')+'</div></div><span class="cxu-badge">Free</span></div>'+quota('请求',account.requests||{},requestNote)+quota('Token',account.tokens||{})+'<div class="cxu-meta">本代理历史累计 '+fmt(observedTokens)+' tokens · 更新于 '+escapeHTML(updated)+'</div></article>'};
function render(error=''){if(!page)return;const accounts=lastAccounts||[],known=accounts.filter(a=>a.known&&a.free_mode).length,refreshText=lastRefresh?lastRefresh.toLocaleTimeString():'尚未刷新',seconds=nextRefresh?Math.max(0,Math.ceil((nextRefresh-Date.now())/1000)):30,paged=paginate(accounts),refreshStatus=autoRefreshEnabled?'约 '+seconds+' 秒后自动刷新':'自动刷新已关闭';page.style.setProperty('--cxu-columns',effectiveColumns);const controls='<div class="cxu-controls"><label class="cxu-control">列数 <select class="cxu-select" data-cxu-columns>'+optionHTML(columnOptions,columnPreference,value=>value==='auto'?'自动':value+' 列')+'</select></label><label class="cxu-control">每页行数 <select class="cxu-select" data-cxu-rows>'+optionHTML(rowOptions,rowsPerPage,value=>value+' 行')+'</select></label><span class="cxu-muted">当前 '+effectiveColumns+' 列 · 每页 '+paged.pageSize+' 个账号</span></div>';const pager=accounts.length?'<div class="cxu-pager"><button class="cxu-page-button" data-cxu-prev '+(currentPage<=1?'disabled':'')+'>上一页</button><span>第 '+currentPage+' / '+paged.totalPages+' 页 · 共 '+accounts.length+' 个账号</span><button class="cxu-page-button" data-cxu-next '+(currentPage>=paged.totalPages?'disabled':'')+'>下一页</button></div>':'';page.innerHTML='<div class="cxu-page-head"><div><h1 class="cxu-page-title">Grok Free 额度</h1><div class="cxu-page-subtitle">进度条使用最近一次上游额度响应；本代理历史累计仅用于展示，不参与当前额度计算。</div></div></div><div class="cxu-summary"><span class="cxu-pill">账号 '+accounts.length+'</span><span class="cxu-pill">已知额度 '+known+'</span><span class="cxu-pill">最近刷新 '+refreshText+'</span><label class="cxu-control"><input type="checkbox" data-cxu-auto-refresh '+(autoRefreshEnabled?'checked':'')+'> 自动刷新</label><span class="cxu-muted" data-cxu-countdown>'+refreshStatus+'</span><button class="cxu-refresh" type="button" '+(inFlight?'disabled':'')+'>立即刷新</button></div>'+controls+(error?'<div class="cxu-error">'+escapeHTML(error)+'</div>':'')+(accounts.length?'<div class="cxu-grid">'+paged.items.map(card).join('')+'</div>'+pager:'<div class="cxu-empty">'+(lastAccounts?'暂无 xAI OAuth 账号':'正在读取账号额度…')+'</div>');page.querySelector('.cxu-refresh').addEventListener('click',()=>load(true));page.querySelector('[data-cxu-auto-refresh]').addEventListener('change',event=>{autoRefreshEnabled=event.target.checked;localStorage.setItem(AUTO_REFRESH_KEY,String(autoRefreshEnabled));if(autoRefreshEnabled)startTimers();else stopTimers();render(error)});page.querySelector('[data-cxu-columns]').addEventListener('change',event=>{columnPreference=event.target.value;localStorage.setItem(COLUMN_KEY,columnPreference);currentPage=1;render(error)});page.querySelector('[data-cxu-rows]').addEventListener('change',event=>{rowsPerPage=Number(event.target.value);localStorage.setItem(ROWS_KEY,String(rowsPerPage));currentPage=1;render(error)});const previous=page.querySelector('[data-cxu-prev]'),next=page.querySelector('[data-cxu-next]');if(previous)previous.addEventListener('click',()=>{currentPage--;render(error)});if(next)next.addEventListener('click',()=>{currentPage++;render(error)})}
function tick(){if(!page)return;const node=page.querySelector('[data-cxu-countdown]');if(node)node.textContent='约 '+Math.max(0,Math.ceil((nextRefresh-Date.now())/1000))+' 秒后自动刷新'}
function stopTimers(){clearInterval(timer);clearInterval(countdown);timer=null;countdown=null}
function startTimers(){stopTimers();if(!autoRefreshEnabled||!active()||document.hidden)return;nextRefresh=Date.now()+INTERVAL;timer=setInterval(()=>load(false),INTERVAL);countdown=setInterval(tick,1000);tick()}
async function load(manual){if(inFlight||!active())return;const key=managementKey();if(!key){render('未读取到管理密钥，请重新登录管理面板。');return}inFlight=true;render();try{const response=await fetch('/v0/management/xai-free-usage',{method:'GET',headers:{Authorization:'Bearer '+key}});if(!response.ok)throw new Error('HTTP '+response.status);const data=await response.json();lastAccounts=Array.isArray(data.accounts)?data.accounts:[];lastRefresh=new Date();render()}catch(error){render('额度读取失败：'+String(error&&error.message||error))}finally{inFlight=false;render();if(manual||active())startTimers()}}
function mount(){if(page)return;page=document.createElement('section');page.id=PAGE_ID;page.setAttribute('aria-label','Grok Free usage');document.body.appendChild(page);positionPage();render();load(false);if(autoRefreshEnabled)startTimers()}
function unmount(){stopTimers();if(page)page.remove();page=null}
function syncRoute(){ensureNav();if(active())mount();else unmount();if(nav)nav.classList.toggle('cxu-nav-active',active())}
function onVisible(){if(document.hidden)stopTimers();else if(active()&&autoRefreshEnabled){load(false);startTimers()}}
const originalPushState=history.pushState.bind(history),originalReplaceState=history.replaceState.bind(history);
history.pushState=function(...args){const result=originalPushState(...args);queueMicrotask(syncRoute);return result};
history.replaceState=function(...args){const result=originalReplaceState(...args);queueMicrotask(syncRoute);return result};
addEventListener('hashchange',syncRoute);addEventListener('popstate',syncRoute);addEventListener('resize',()=>{positionPage();if(page){const previous=effectiveColumns;effectiveColumns=calculateColumns();if(previous!==effectiveColumns)render()}});document.addEventListener('visibilitychange',onVisible);
observer=new MutationObserver(()=>{ensureNav();if(active()&&!page)mount()});observer.observe(document.documentElement,{childList:true,subtree:true});
ensureNav();syncRoute();
})();
</script>
`
